"""Script de ejecución del experimento federado basado en imágenes.Este archivo está pensado para lanzarse directamente desde Spydero desde una terminal, actuando como punto de entrada del pipelineimage-based del proyecto."""from pathlib import Pathimport sysimport logging# ============================================================# AJUSTE DEL PATH PARA SPYDER# ============================================================PROJECT_ROOT = Path.cwd().resolve().parentSRC_DIR = PROJECT_ROOT / "src"if str(SRC_DIR) not in sys.path:    sys.path.insert(0, str(SRC_DIR))# ============================================================# IMPORTS DEL PROYECTO# ============================================================from federated_skin.config.paths import (    METADATA_PATH,    IMAGES_DIR,    FINAL_MODEL_PATH,    BEST_BAL_MODEL_PATH,    BEST_F1_MODEL_PATH,    HISTORY_PATH,    PLOT_PATH,    create_directories,    check_input_paths,)from federated_skin.config.settings import get_default_configfrom federated_skin.federation.image_experiment import FederatedImageExperimentfrom federated_skin.reporting.reports import (    save_history,    plot_history,    print_final_summary,)# ============================================================# LOGGING# ============================================================logging.basicConfig(level=logging.INFO, format="%(levelname)s | %(message)s")LOGGER = logging.getLogger("run_federated_images")# ============================================================# CONFIGURACIÓN# ============================================================create_directories()check_input_paths()config = get_default_config()config.image_model_type = "cnn"config.image_input_mode = "preprocessed"# config.image_input_mode = "segmented"# config.image_input_mode = "preprocessed_plus_mask"# ============================================================# EXPERIMENTO FEDERADO BASADO EN IMAGEN# ============================================================experiment = FederatedImageExperiment(    metadata_path=METADATA_PATH,    images_dir=IMAGES_DIR,    config=config,    logger=LOGGER,)result = experiment.run()# ============================================================# GUARDADO DE MODELOS# ============================================================result.final_model.save(FINAL_MODEL_PATH)result.best_balanced_model.save(BEST_BAL_MODEL_PATH)result.best_macro_f1_model.save(BEST_F1_MODEL_PATH)# ============================================================# GUARDADO DE HISTÓRICO Y FIGURA# ============================================================save_history(result.history_df, HISTORY_PATH)plot_history(result.history_df, PLOT_PATH, show=True)# ============================================================# MÉTRICAS FINALES SOBRE TEST# ============================================================# En esta fase inicial del pipeline image-based dejamos la evaluación# final resumida en el histórico federado y en la selección de mejores# rondas. El reporting detallado por clases puede añadirse después,# cuando se consolide la parte de inferencia batch sobre imagen.final_metrics = result.history_df.iloc[-1].to_dict()LOGGER.info("Modelo final guardado en: %s", FINAL_MODEL_PATH)LOGGER.info("Mejor modelo por balanced_accuracy guardado en: %s", BEST_BAL_MODEL_PATH)LOGGER.info("Mejor modelo por macro_f1 guardado en: %s", BEST_F1_MODEL_PATH)LOGGER.info("Histórico guardado en: %s", HISTORY_PATH)LOGGER.info("Gráfica guardada en: %s", PLOT_PATH)print_final_summary(    history_df=result.history_df,    best_balanced_round=result.best_balanced_round,    best_macro_f1_round=result.best_macro_f1_round,    final_metrics={        "accuracy": result.history_df.iloc[-1]["accuracy"],        "balanced_accuracy": result.history_df.iloc[-1]["balanced_accuracy"],        "macro_f1": result.history_df.iloc[-1]["macro_f1"],    },    best_bal_metrics={        "accuracy": result.history_df["accuracy"].max(),        "balanced_accuracy": result.history_df["balanced_accuracy"].max(),        "macro_f1": result.history_df.loc[            result.history_df["balanced_accuracy"].idxmax(),            "macro_f1",        ],    },    best_f1_metrics={        "accuracy": result.history_df.loc[            result.history_df["macro_f1"].idxmax(),            "accuracy",        ],        "balanced_accuracy": result.history_df.loc[            result.history_df["macro_f1"].idxmax(),            "balanced_accuracy",        ],        "macro_f1": result.history_df["macro_f1"].max(),    },    report_text="Reporte detallado por clases pendiente de integrar en la rama image-based.",    tail_rows=10,)